// Conditional rendering
return isFetching || !data
  ? <MCCircularLoader fillParent />
  : <EntityDetail entity={data} />;`,tier:2},{name:"MCConfirmDialog",path:"@moloco/moloco-cloud-react-ui",description:"Confirmation dialog with customizable cancel and confirm buttons. Used for destructive action confirmations.",importPath:"@moloco/moloco-cloud-react-ui",importStatement:"import { MCConfirmDialog } from '@moloco/moloco-cloud-react-ui';",when_to_use:["Destructive action confirmations (delete, discard changes, archive)","When the user must explicitly confirm or cancel before a dangerous operation","Alert-style dialogs requiring immediate user attention"],do_not_use:["For non-destructive confirmations — use MCCommonDialog","For complex forms inside a dialog — use MCCommonDialog with form content","For informational messages — use toast/snackbar notifications"],compositions:{must_be_inside:[],commonly_paired_with:["MCIcon","MCButton2"]},props:[{name:"isOpen",type:"boolean",required:!0,description:"Controls dialog visibility"},{name:"title",type:"ReactNode",required:!0,description:"Dialog title"},{name:"cancelButtonOptions",type:"{ label: string; leftIcon?: ReactNode; onClick: () => void; disabled?: boolean }",required:!0,description:"Cancel button configuration"},{name:"confirmButtonOptions",type:"{ label: string; color?: string; leftIcon?: ReactNode; onClick: () => void; disabled?: boolean }",required:!0,description:"Confirm button configuration"},{name:"onClose",type:"() => void",required:!0,description:"Close handler"},{name:"disableCloseButton",type:"boolean",required:!1,description:"Disables the X close button"}],semantic_actions:[{action:"User confirms the destructive action by clicking the confirm button",triggers:"confirmButtonOptions.onClick callback → mutation executes; onClose() called"},{action:"User cancels by clicking the cancel button",triggers:"cancelButtonOptions.onClick callback → onClose() → isOpen = false"},{action:"User dismisses by pressing Escape or clicking the X button",triggers:"onClose() → isOpen = false"}],data_flow:{input:"props (isOpen boolean, title, cancelButtonOptions, confirmButtonOptions)",output:"confirmButtonOptions.onClick callback — mutation trigger; cancelButtonOptions.onClick + onClose — close dialog",side_effects:["background content aria-hidden=true while open","focus trapped inside dialog"]},states:[{name:"default",description:"Normal resting state"},{name:"open",description:"Dialog is visible"}],accessibility:{role:"alertdialog with aria-modal=true",ariaLabel:"aria-labelledby pointing to title; aria-describedby pointing to body message text",keyboardInteraction:["Tab: Cycle focus between cancel and confirm buttons (trapped inside dialog)","Shift+Tab: Cycle focus backwards","Enter/Space: Activate focused button","Escape: Close dialog (equivalent to cancel)"],screenReaderAnnouncement:"On open immediately announces: {title}, alert dialog. Body message also announced. Focus moves to first button.",notes:["alertdialog role causes immediate announcement unlike dialog — appropriate for destructive confirmations","Focus must be trapped inside and return to trigger on close","Cancel button should be focused first (safe default action)"]},dos:["Use for destructive action confirmations","Make cancel the safe/default action","Clearly describe consequences in body text"],donts:["Don't use for non-destructive confirmations","Don't make the destructive action the default/highlighted button"],example:`<MCConfirmDialog
